INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (2, "vo_minigame_1013_icon_2_002_001", "vo_minigame_1013_icon_1_002_001", 2, "調子が上がって\nきたなっ", 3000, 1, 2, 1000, "訓練はまだ\nここからですわ");
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (2, "vo_minigame_1013_icon_2_003_001", "vo_minigame_1013_icon_1_003_001", 2, "ほらほら、\nまだいけるだろ？", 3000, 2, 2, 5000, "クスクス、悪くない\n流れですわね");
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (2, "vo_minigame_1013_icon_2_004_001", "vo_minigame_1013_icon_1_004_001", 2, "へへっ、おまえら\nやるじゃねえか！", 3000, 3, 3, 10000, "すばらしい\n記録ですわ");
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (2, "vo_minigame_1013_icon_2_005_001", "vo_minigame_1013_icon_1_005_001", 3, "あたしたちはまだ\n止まらねえぜ！", 3000, 4, 3, 10000, "乗りに乗って\nいますわね");
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (2, "vo_minigame_1013_icon_2_005_002", "vo_minigame_1013_icon_1_005_002", 3, "見てろよ！\nマコト班の快進撃だ！", 3000, 5, 3, 10000, "まだまだ行きます\nついてきなさい");
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (2, "vo_minigame_1013_icon_2_005_003", "vo_minigame_1013_icon_1_005_003", 3, "うおぉぉっ！\n絶好調だぜ！", 3000, 6, 3, 10000, "エリコ班の\n本領発揮ですわ！");
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (2, "vo_minigame_1013_icon_2_006_001", "vo_minigame_1013_icon_1_006_001", 4, "どこまで行けるか\n楽しみだなっ！", 3000, 7, 3, 0, "ここからは\n前人未到の領域です！");
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (3, "vo_minigame_1013_icon_2_007_001", "vo_minigame_1013_icon_1_007_001", 5, "まだ諦めんなよっ", 1000, 8, 4, 1, "厄介でしたわ…");
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (3, "vo_minigame_1013_icon_2_007_002", "vo_minigame_1013_icon_1_007_002", 5, "冷やっとしたぜ…！", 1000, 9, 4, 1, "油断大敵です");
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (3, "vo_minigame_1013_icon_2_007_003", "vo_minigame_1013_icon_1_007_003", 5, "弱音を吐くなっ", 1000, 10, 4, 1, "忌々しいっ…");
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (4, "vo_minigame_1013_icon_2_008_001", "vo_minigame_1013_icon_1_008_001", 6, "マコト班集合！", 1500, 11, 3, 99, "大所帯ですわね");
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (4, "vo_minigame_1013_icon_2_008_002", "vo_minigame_1013_icon_1_008_002", 6, "連携してくぞ！", 1500, 12, 3, 99, "エリコ班へようこそ");
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (1, "vo_minigame_1013_icon_2_020_001", "vo_minigame_1013_icon_1_020_001", 8, "みんなに力を！", 3000, 13, 6, 0, "ナナカちゃんに\nお任せあれ");
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (1, "vo_minigame_1013_icon_2_022_001", "vo_minigame_1013_icon_1_022_001", 9, "任せてくれたまえ", 3000, 14, 7, 0, "はっはっは！\n任せろ！");
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (1, "vo_minigame_1013_icon_2_023_001", "vo_minigame_1013_icon_1_023_001", 10, "ほな、いきまひょか", 3000, 15, 8, 0, "どんどんいくわよ");
